 1	import React from 'react';
 2	
 3	import Loading from '@kubevirt-utils/components/Loading/Loading';
 4	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import {
 7	  updateCustomizeInstanceType,
 8	  updateVMCustomizeIT,
 9	  vmSignal,
10	} from '@kubevirt-utils/store/customizeInstanceType';
11	import {
12	  DescriptionList,
13	  Divider,
14	  PageSection,
15	  PageSectionVariants,
16	  Title,
17	} from '@patternfly/react-core';
18	import InitialRunTabCloudinit from '@virtualmachines/details/tabs/configuration/initialrun/components/InitialRunTabCloudinit';
19	import InitialRunTabSysprep from '@virtualmachines/details/tabs/configuration/initialrun/components/InitialRunTabSysprep';
20	
21	const CustomizeInstanceTypeInitialRunTab = () => {
22	  const { t } = useKubevirtTranslation();
23	  const vm = vmSignal.value;
24	
25	  if (!vm) {
26	    return <Loading />;
27	  }
28	
29	  return (
30	    <PageSection variant={PageSectionVariants.light}>
31	      <Title headingLevel="h2">
32	        <SearchItem id="initial-run">{t('Initial run')}</SearchItem>
33	      </Title>
34	      <DescriptionList className="pf-v6-c-description-list">
35	        <InitialRunTabCloudinit canUpdateVM onSubmit={updateVMCustomizeIT} vm={vm} />
36	        <Divider />
37	        <InitialRunTabSysprep canUpdateVM onSubmit={updateCustomizeInstanceType} vm={vm} />
38	      </DescriptionList>
39	    </PageSection>
40	  );
41	};
42	
43	export default CustomizeInstanceTypeInitialRunTab;

